# 2026 Q1 Date Conversion Script# Convert 2025 Q4 test data to 2026-01-01 ~ 2026-01-15$BaseDir = "c:\Users\tony1\Desktop\UI UX-20251218(2313) - MIKE"$OutputDir = Join-Path $BaseDir "2026Q1_Medical_Quality_Test_Data"Write-Host "====================================================================================" -ForegroundColor CyanWrite-Host "2026 Q1 Test Data Date Conversion Tool" -ForegroundColor YellowWrite-Host "Target: 2026-01-01 to 2026-01-15 (15 days)" -ForegroundColor YellowWrite-Host "====================================================================================" -ForegroundColor CyanWrite-Host ""# Create output directoryif (-not (Test-Path $OutputDir)) {    New-Item -ItemType Directory -Path $OutputDir | Out-Null    Write-Host "Created output directory" -ForegroundColor Green}# Date conversion functionfunction ConvertDate {    param([string]$DateStr)        if ([string]::IsNullOrWhiteSpace($DateStr)) { return $DateStr }        try {        $cleanDate = $DateStr -replace 'Z$', '' -replace '\+\d{2}:\d{2}$', ''        $dt = [datetime]::Parse($cleanDate)                if ($dt.Year -eq 2025 -and $dt.Month -ge 10 -and $dt.Month -le 12) {            $offset = 0            if ($dt.Month -eq 10) { $offset = [math]::Floor(($dt.Day - 1) / 31 * 5) }            elseif ($dt.Month -eq 11) { $offset = 5 + [math]::Floor(($dt.Day - 1) / 30 * 5) }            elseif ($dt.Month -eq 12) { $offset = 10 + [math]::Floor(($dt.Day - 1) / 31 * 5) }                        $offset = [math]::Min($offset, 14)            $newDate = ([datetime]"2026-01-01").AddDays($offset).Date.Add($dt.TimeOfDay)                        if ($DateStr -match '\+\d{2}:\d{2}$') {                $tz = $DateStr -replace '^.*(\+\d{2}:\d{2})$', '$1'                return $newDate.ToString("yyyy-MM-ddTHH:mm:ss") + $tz            }            elseif ($DateStr -match 'Z$') {                return $newDate.ToString("yyyy-MM-ddTHH:mm:ss") + "Z"            }            elseif ($DateStr -match 'T') {                return $newDate.ToString("yyyy-MM-ddTHH:mm:ss")            }            else {                return $newDate.ToString("yyyy-MM-dd")            }        }    } catch {}        return $DateStr}# Recursive date conversionfunction ConvertDates {    param($obj)        if ($obj -is [System.Collections.IDictionary]) {        $keys = @($obj.Keys)        foreach ($key in $keys) {            $val = $obj[$key]            if ($val -is [string] -and $key -match 'date|time|start|end|issued|created|authored|birthDate|deceasedDateTime|authoredOn|recordedDate') {                $obj[$key] = ConvertDate $val            }            elseif ($val -is [System.Collections.IDictionary] -or $val -is [System.Collections.IList]) {                ConvertDates $val            }        }    }    elseif ($obj -is [System.Collections.IList]) {        for ($i = 0; $i -lt $obj.Count; $i++) {            if ($obj[$i] -is [System.Collections.IDictionary] -or $obj[$i] -is [System.Collections.IList]) {                ConvertDates $obj[$i]            }        }    }}# Find files$patterns = @("test_data*.json", "Cesarean*.json", "ESWL*.json", "Dementia*.json", "Fibroid*.json", "Knee*.json", "Surgical*.json", "First_Time*.json", "Same_Hospital*.json")$files = @()foreach ($p in $patterns) {    $files += Get-ChildItem -Path $BaseDir -Filter $p -File}$exclude = @('complete_test_data', 'eswl_query', 'cors', '_2026Q1', 'conversion_log')$files = $files | Where-Object {    $n = $_.Name    $ok = $true    foreach ($e in $exclude) { if ($n -like "*$e*") { $ok = $false; break } }    $ok} | Sort-Object Name -Uniqueif ($files.Count -eq 0) {    Write-Host "No files found!" -ForegroundColor Yellow    exit}Write-Host "Found $($files.Count) files to convert`n" -ForegroundColor Green# Convert files$success = 0$fail = 0foreach ($file in $files) {    try {        Write-Host "[$($success + $fail + 1)/$($files.Count)] Processing: $($file.Name)" -ForegroundColor Cyan                $json = Get-Content $file.FullName -Raw -Encoding UTF8 | ConvertFrom-Json        ConvertDates $json                $newName = $file.Name -replace '_2025Q4', '' -replace '2025Q4', '' -replace '\.json$', '_2026Q1.json'        $outPath = Join-Path $OutputDir $newName                $json | ConvertTo-Json -Depth 100 | Set-Content $outPath -Encoding UTF8                Write-Host "  -> Saved: $newName" -ForegroundColor Green        $success++    }    catch {        Write-Host "  -> Error: $($_.Exception.Message)" -ForegroundColor Red        $fail++    }}Write-Host "`n====================================================================================" -ForegroundColor CyanWrite-Host "Conversion Complete!" -ForegroundColor GreenWrite-Host "Success: $success files" -ForegroundColor GreenWrite-Host "Failed: $fail files" -ForegroundColor $(if ($fail -gt 0) {"Red"} else {"Green"})Write-Host "Output: $OutputDir" -ForegroundColor CyanWrite-Host "====================================================================================" -ForegroundColor Cyan